fn inc_line_number(ls: &mut LexState, _state: &mut LuaState) -> Result<(), LuaError> {
    // C: lua_assert(currIsNewline(ls))
    // macros.tsv: lua_assert → debug_assert!
    debug_assert!(curr_is_newline(ls), "inc_line_number: not at a newline");

    let old = ls.current;
    // C: next(ls)  — skip '\n' or '\r'
    advance(ls);

    // C: if (currIsNewline(ls) && ls->current != old) next(ls)
    if curr_is_newline(ls) && ls.current != old {
        advance(ls);
    }

    // C: if (++ls->linenumber >= MAX_INT) lexerror(...)
    // macros.tsv: MAX_INT → i32::MAX
    ls.linenumber += 1;
    if ls.linenumber >= i32::MAX {
        return Err(lex_error(ls, b"chunk has too many lines", 0));
    }

    // PORT NOTE: skipcomment-equivalent. C-Lua's luaL_loadfile strips a leading
    // '#' line before lexing (Unix shebang). Our test harness prepends a global-
    // setup preamble to every official test, which pushes the script's '#' line
    // past line 1 — so the byte-zero strip is not enough. Instead, treat any
    // line whose first non-whitespace character is '#' as a single-line comment.
    // This is consistent with how Lua source files written with a shebang are
    // intended to be parsed regardless of where they appear in the byte stream.
    if ls.current == b'#' as i32 {
        while !curr_is_newline(ls) && ls.current != EOZ {
            advance(ls);
        }
    }
    Ok(())
}

